mapper.select:
SELECT r.*, -- review 테이블 전체 m.member_name, -- 작성자 이름 m.member_nick -- 작성자 닉네임 FROM review r LEFT JOIN member m ON r.member_idx = m.member_idx WHERE r.book_id = #{book_id}
ORDER BY r.review_score DESC
ORDER BY r.review_date DESC
LIMIT #{pageStart}, #{perPageNum}

mapper.delete:
DELETE FROM review
WHERE review_id = #{review_id}
  AND member_idx = #{member_idx}

mapper.select:
SELECT IFNULL(AVG(review_score), 0)
FROM review
WHERE book_id = #{book_id}
